#include "streamcluster_header.h" // Changed from .cu to .h
#include <omp.h>

using namespace std;

#define THREADS_PER_BLOCK 512
#define MAXBLOCKS 65536
#define CUDATIME

// host memory
float *work_mem_h;
float *coord_h;

// device memory (simulated with host pointers for OpenMP)
float *work_mem_d;
float *coord_d;
int   *center_table_d;
bool  *switch_membership_d;
Point *p;

static int iter = 0;		// counter for total# of iteration


//=======================================
// Euclidean Distance
//=======================================
// This function is now part of the main loop and not a separate kernel.
// It will be called from within the parallelized region.

//=======================================
// Kernel - Compute Cost (Simulated)
//=======================================
// This function is now integrated into the pgain function and executed
// within an OpenMP parallel region.

//=======================================
// Allocate Device Memory (Simulated)
//=======================================
void allocDevMem(int num, int dim)
{
	// In OpenMP, we can directly use host memory.
	// For consistency with the CUDA version, we'll allocate host memory
	// and assign pointers.
	center_table_d = (int*) malloc( num * sizeof(int) );
	switch_membership_d = (bool*) malloc( num * sizeof(bool) );
	p = (Point*) malloc( num * sizeof(Point) );
	coord_d = (float*) malloc(num * dim * sizeof(float));
}

//=======================================
// Allocate Host Memory
//=======================================
void allocHostMem(int num, int dim)
{
	coord_h	= (float*) malloc( num * dim * sizeof(float) );
}

//=======================================
// Free Device Memory (Simulated)
//=======================================
void freeDevMem()
{
	free(center_table_d);
	free(switch_membership_d);
	free(p);
	free(coord_d);
}

//=======================================
// Free Host Memory
//=======================================
void freeHostMem()
{
	free(coord_h);
}

//=======================================
// pgain Entry - OpenMP SETUP + PARALLEL EXECUTION
//=======================================
float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
							double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{	
#ifdef CUDATIME
	double tmp_t;
	double start_time, stop_time;

	start_time = omp_get_wtime();
#endif

	int stride	= *numcenters + 1;			// size of each work_mem segment
	int K		= *numcenters ;				// number of centers
	int num		=  points->num;				// number of points
	int dim		=  points->dim;				// number of dimension
	int nThread =  num;						// number of threads == number of data points

	//=========================================
	// ALLOCATE HOST MEMORY + DATA PREPARATION
	//=========================================
	work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float) );
	// Only on the first iteration
	if(0 == iter)
	{
		allocHostMem(num, dim);
	}

	// build center-index table
	int count = 0;
	for( int i=0; num > i; i++)
	{
		if( is_center[i] )
		{
			center_table[i] = count++;
		}
	}

	// Extract 'coord'
	// Only if first iteration OR coord has changed
	if(isCoordChanged || 0 == iter)
	{
		for(int i=0; dim > i; i++)
		{
			for(int j=0; num > j; j++)
			{
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
			}
		}
	}

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*serial_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// ALLOCATE GPU MEMORY (Simulated)
	//=======================================
	// Only on the first iteration
	if( 0 == iter )
	{
		allocDevMem(num, dim);
	}

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*alloc_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// CPU-TO-GPU MEMORY COPY (Simulated)
	//=======================================
	// Only if first iteration OR coord has changed
	if(isCoordChanged || 0 == iter)
	{
		memcpy(coord_d,  coord_h,	 num * dim * sizeof(float));
	}
	memcpy(center_table_d,  center_table,  num * sizeof(int));
	memcpy(p,  points->p,				   num * sizeof(Point));

	// Initialize switch_membership and work_mem
	memset(switch_membership_d, 0, num * sizeof(bool));
	memset(work_mem_d, 0, stride * (nThread + 1) * sizeof(float));

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*cpu_to_gpu_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// KERNEL: CALCULATE COST (Parallelized)
	//=======================================

	// The kernel logic is now inside the parallel region.
	// We simulate the kernel execution by parallelizing the loop.

	#pragma omp parallel num_threads(nThread)
	{
		// block ID and global thread ID (simulated)
		const int tid = omp_get_thread_num();

		if(num > tid)
		{
			float *lower = &work_mem_d[tid*stride];

			// cost between this point and point[x]: euclidean distance multiplied by weight
			float x_cost = 0.0;
			for(int i = 0; dim > i; i++){
				float tmp = coord_d[(i*num)+tid] - coord_d[(i*num)+x];
				x_cost = x_cost + (tmp * tmp);
			}
			x_cost *= p[tid].weight;

			// if computed cost is less then original (it saves), mark it as to reassign
			if ( p[tid].cost > x_cost )
			{
				switch_membership_d[tid] = 1;
				lower[K] += x_cost - p[tid].cost;
			}
			// if computed cost is larger, save the difference
			else
			{
				lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
			}
		}
	}

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*kernel_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// GPU-TO-CPU MEMORY COPY (Simulated)
	//=======================================
	memcpy(work_mem_h, 		  work_mem_d, 	stride * (nThread + 1) * sizeof(float));
	memcpy(switch_membership, switch_membership_d,	 num * sizeof(bool));

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*gpu_to_cpu_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// CPU (SERIAL) WORK
	//=======================================
	int number_of_centers_to_close = 0;
	float gl_cost_of_opening_x = z;
	float *gl_lower = &work_mem_h[stride * nThread];
	// compute the number of centers to close if we are to open i
	for(int i=0; num > i; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; num > j; j++ )
			{
				low = low + (work_mem_h[ j*stride + center_table[i] ]);
			}

		    gl_lower[center_table[i]] = low;

		    if ( 0 < low )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x = gl_cost_of_opening_x + (work_mem_h[i*stride+K]);
	}

	//if opening a center at x saves cost (i.e. cost is negative) do so; otherwise, do nothing
	if ( 0 > gl_cost_of_opening_x )
	{
		for(int i = 0; num > i; i++)
		{
			bool close_center = 0 < gl_lower[center_table[points->p[i].assign]] ;
			if ( switch_membership[i] || close_center )
			{
				// Re-calculate distance here as it's not available from kernel
				float distance = 0.0;
				for(int d_idx = 0; dim > d_idx; d_idx++){
					float tmp = points->p[i].coord[d_idx] - points->p[x].coord[d_idx];
					distance += tmp * tmp;
				}
				points->p[i].cost = distance * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		for(int i = 0; num > i; i++)
		{
			if( is_center[i] && 0 < gl_lower[center_table[i]] )
			{
				is_center[i] = false;
			}
		}

		if( 0 <= x && num > x)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	//=======================================
	// DEALLOCATE HOST MEMORY
	//=======================================
	free(work_mem_h);


#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*serial_t += (stop_time - start_time);

	start_time = omp_get_wtime();
#endif

	//=======================================
	// DEALLOCATE GPU MEMORY (Simulated)
	//=======================================
	// Freeing simulated device memory
	if (0 == iter) { // Free only on the last iteration to match CUDA behavior
		freeDevMem();
	}

#ifdef CUDATIME
	stop_time = omp_get_wtime();
	*free_t += (stop_time - start_time);
#endif
	iter++;
	return -gl_cost_of_opening_x;
}
